### TASK 5

```python
class LFUCache:
    def __init__(self, capacity):
        self.capacity = capacity
        self.store = {}          # key -> value (currently stored)
        self.counts = {}         # key -> permanent use-count (never reset)
        self.tick = 0
        self.recency = {}        # key -> last-access tick (for currently stored)

    def _touch(self, key):
        self.tick += 1
        self.recency[key] = self.tick
        self.counts[key] = self.counts.get(key, 0) + 1

    def get(self, key):
        if key not in self.store:
            return -1
        self._touch(key)
        return self.store[key]

    def put(self, key, value):
        if self.capacity == 0:
            return
        if key in self.store:
            self.store[key] = value
            self._touch(key)
            return
        if len(self.store) == self.capacity:
            # evict: smallest count, tie-break least-recently-used
            victim = min(self.store, key=lambda k: (self.counts[k], self.recency[k]))
            del self.store[victim]
            del self.recency[victim]
        self.store[key] = value
        self._touch(key)
```

