def schedule(intervals):
    order = sorted(range(len(intervals)),
                   key=lambda i: (intervals[i][1], -intervals[i][0], i))
    sel = []
    last = None
    for i in order:
        s, e = intervals[i]
        if last is None or s > last:
            sel.append([s, e])
            last = e
    return sorted(sel, key=lambda x: (x[0], x[1]))
```

