def measure_at_least(segments, k):
    if not segments:
        return 0.0
    xs = set()
    for s, e, w in segments:
        xs.add(s)
        xs.add(e)
    xs = sorted(xs)
    total = 0.0
    for i in range(len(xs) - 1):
        lo, hi = xs[i], xs[i + 1]
        if hi <= lo:
            continue
        mid = (lo + hi) / 2
        best = None
        for s, e, w in segments:
            if s <= mid <= e:
                if best is None or w > best:
                    best = w
        if best is not None and best >= k:
            total += hi - lo
    return float(total)
